/**
 * Helper class for Min Priority Queue
 * Stores [priority, value]
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    // Comparison function: compares by priority (the first element)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this._compare(index, parentIndex)) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let smallest = index;
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        const n = this.heap.length;

        if (left < n && this._compare(left, smallest)) {
            smallest = left;
        }
        if (right < n && this._compare(right, smallest)) {
            // If priorities are equal, we prefer smaller index for tie-breaking, 
            // but for Dijkstra, we only rely on priority.
            if (this.heap[right][0] < this.heap[smallest][0]) {
                 smallest = right;
            }
        }

        if (smallest !== index) {
            this._swap(index, smallest);
            this._bubbleDown(smallest);
        }
    }

    enqueue(priority, value) {
        this.heap.push([priority, value]);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}


function solve(nums, queries) {
    const N = nums.length;

    // 1. Precalculate closest(x)
    const closest = new Array(N);

    if (N === 1) {
        // Should not happen based on constraints (N >= 2), but for safety
        return new Array(queries.length).fill(0);
    }

    for (let x = 0; x < N; x++) {
        let bestDiff = Infinity;
        let bestY = -1;

        // Check left neighbor x-1
        if (x > 0) {
            const diff = Math.abs(nums[x] - nums[x - 1]);
            if (diff < bestDiff) {
                bestDiff = diff;
                bestY = x - 1;
            } else if (diff === bestDiff) {
                // Tie-breaking: choose smaller index. x-1 is smaller than x+1.
                if (x - 1 < bestY) {
                    bestY = x - 1;
                }
            }
        }

        // Check right neighbor x+1
        if (x < N - 1) {
            const diff = Math.abs(nums[x] - nums[x + 1]);
            if (diff < bestDiff) {
                bestDiff = diff;
                bestY = x + 1;
            } else if (diff === bestDiff) {
                // Tie-breaking: choose smaller index. 
                // If bestY is currently x-1, we keep it. Otherwise, compare.
                if (x + 1 < bestY || bestY === -1) {
                     // Since we checked x-1 first, if bestY was set, it's smaller or equal to x-1.
                     // If diff equals bestDiff, and bestY was set to x-1, we prefer x-1.
                     // If bestY is -1 (only possible if x=0 and N=2, and x+1=1), we set it.
                     if (x - 1 === undefined || x - 1 > x + 1) { // Should only trigger if x=0 and bestY=-1
                        bestY = x + 1;
                     }
                }
            }
        }

        // Re-evaluate tie-breaking logic carefully for general case 0 < x < N-1
        if (x > 0 && x < N - 1) {
             const d_left = Math.abs(nums[x] - nums[x - 1]);
             const d_right = Math.abs(nums[x] - nums[x + 1]);

             if (d_left < d_right) {
                 closest[x] = x - 1;
             } else if (d_right < d_left) {
                 closest[x] = x + 1;
             } else { // d_left == d_right
                 // Choose smaller index
                 closest[x] = x - 1;
             }
        } else if (x === 0 && N > 1) {
            closest[x] = 1;
        } else if (x === N - 1 && N > 1) {
            closest[x] = N - 2;
        }
    }

    const results = [];

    // 2. Process Queries using Dijkstra's algorithm
    for (const [l, r] of queries) {
        if (l === r) {
            results.push(0);
            continue;
        }

        // Distance array initialization
        const dist = new Array(N).fill(Infinity);
        dist[l] = 0;

        // Min Priority Queue: stores [cost, index]
        const pq = new MinPriorityQueue();
        pq.enqueue(0, l);

        while (!pq.isEmpty()) {
            const [d_x, x] = pq.dequeue();

            if (d_x > dist[x]) {
                continue;
            }

            if (x === r) {
                // Target reached
                results.push(d_x);
                break;
            }

            // --- Relaxation Step 1: Move to closest(x) (Cost 1) ---
            const y_closest = closest[x];
            // Since movement is assumed bidirectional for shortest path calculation
            if (dist[x] + 1 < dist[y_closest]) {
                dist[y_closest] = dist[x] + 1;
                pq.enqueue(dist[y_closest], y_closest);
            }


            // --- Relaxation Step 2: Move to any y (Cost |nums[x] - nums[y]|) ---
            // This step leads to O(N^2) complexity per query, but is required by the problem statement.
            for (let y = 0; y < N; y++) {
                if (x === y) continue;

                const cost_type1 = Math.abs(nums[x] - nums[y]);
                const new_dist = dist[x] + cost_type1;

                if (new_dist < dist[y]) {
                    dist[y] = new_dist;
                    pq.enqueue(new_dist, y);
                }
            }
        }

        // If the loop finishes without reaching r (shouldn't happen given Type 1 moves always exist)
        if (dist[r] !== Infinity) {
             results.push(dist[r]);
        } else {
             // Fallback, although unreachable if N >= 2
             results.push(-1); 
        }
    }

    return results;
}

