/**
 * Helper class for Min Priority Queue
 * Stores [priority, value]
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    // Comparison function: compares by priority (the first element)
    _compare(i, j) {
        return this.heap[i][0] < this.heap[j][0];
    }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this._compare(index, parentIndex)) {
                this._swap(index, parentIndex);
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    _bubbleDown(index) {
        let smallest = index;
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        const n = this.heap.length;

        if (left < n && this._compare(left, smallest)) {
            smallest = left;
        }
        if (right < n && this._compare(right, smallest)) {
            // If priorities are equal, we prefer smaller index for tie-breaking, 
            // but for Dijkstra, we only rely on priority.
            if (this.heap[right][0] < this.heap[smallest][0]) {
                 smallest = right;
            }
        }

        if (smallest !== index) {
            this._swap(index, smallest);
            this._bubbleDown(smallest);
        }
    }

    enqueue(priority, value) {
        this.heap.push([priority, value]);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._bubbleDown(0);
        return root;
    }
}


